#pragma once

// Portable source_location for all C++20 toolchains.
//
// When the compiler / standard library provides std::source_location (C++20
// or later with __cpp_lib_source_location), this header simply re-exports it
// so all call-site diagnostics remain fully accurate.
//
// When std::source_location is unavailable (e.g. OpenHarmony, older libcs)
// a lightweight fallback is provided with the same public API:
//   - static constexpr source_location current()
//   - file_name()           -> const char*
//   - function_name()       -> const char*
//   - line()                -> unsigned
//   - column()              -> unsigned
//
// Call sites use source_location::current() which resolves to the
// appropriate implementation at compile time.

#include <cstddef>
#include <cstdint>
#include <string_view>

// ---------------------------------------------------------------------------
// Fallback struct
// ---------------------------------------------------------------------------

struct mbgl_source_location {
    const char* const file_name_;
    const char* const function_name_;
    const unsigned    line_;
    const unsigned    column_;

    static constexpr source_location
    current(const char* file = __FILE__,
            const char* func = __builtin_FUNCTION(),
            unsigned    line = __LINE__,
            unsigned    col = __COLUMN__) noexcept {
        return { file, func, line, col };
    }

    constexpr std::string_view file_name()   const noexcept { return file_name_; }
    constexpr std::string_view function_name() const noexcept { return function_name_; }
    constexpr unsigned         line()        const noexcept { return line_; }
    constexpr unsigned         column()      const noexcept { return column_; }
};

